"""Core module: ForgeError exception and create_forge factory."""
import time
import uuid


class ForgeError(Exception):
    """Base exception for TaskForge scheduling errors."""

    def __init__(self, message, code=None):
        super().__init__(message)
        self.code = code
        self.timestamp = time.time()

    def __repr__(self):
        return f"ForgeError({self.args[0]!r}, code={self.code})"


class ValidationError(ForgeError):
    """Raised when task validation fails."""
    pass


class TimeoutError(ForgeError):
    """Raised when a task exceeds its deadline."""
    pass


def create_forge(name, config=None, strict=False):
    """Create a new TaskForge instance.

    Args:
        name: Identifier for this forge.
        config: Optional configuration dict.
        strict: If True, raises on invalid config.

    Returns:
        A configured TaskForge instance.
    """
    if config is None:
        config = {}
    if strict and not isinstance(config, dict):
        raise ForgeError("Config must be a dict", code="INVALID_CONFIG")
    return TaskForge(forge_id=str(uuid.uuid4())[:8], name=name, config=config)


class TaskForge:
    """Main scheduler instance."""

    def __init__(self, forge_id, name, config):
        self.forge_id = forge_id
        self.name = name
        self.config = config
        self._tasks = {}
        self._running = False

    def start(self):
        if self._running:
            raise ForgeError("Forge already running")
        self._running = True

    def stop(self):
        if not self._running:
            raise ForgeError("Forge not running")
        self._running = False

    def submit(self, task_name, payload=None):
        if not self._running:
            raise ForgeError("Cannot submit: forge not running")
        task_id = str(uuid.uuid4())[:8]
        self._tasks[task_id] = {"name": task_name, "payload": payload or {}}
        return task_id

