"""Hook system for task lifecycle events."""
from taskforge.core import ForgeError, create_forge


class HookManager:
    """Manages lifecycle hooks. Raises ForgeError on failures."""

    def __init__(self):
        self._hooks = {"pre_execute": [], "post_execute": [], "on_error": []}
        self._forge = create_forge("hooks", {"max_workers": 1})

    def register(self, event, callback):
        """Register hook. Raises ForgeError if event unknown."""
        if event not in self._hooks:
            raise ForgeError(f"Unknown event: '{event}'")
        self._hooks[event].append(callback)

    def fire(self, event, context=None):
        """Fire hooks. Raises ForgeError if any hook fails."""
        if event not in self._hooks:
            raise ForgeError(f"Cannot fire: '{event}'")
        results = []
        for cb in self._hooks[event]:
            try:
                results.append(cb(context or {}))
            except Exception as e:
                if event != "on_error":
                    raise ForgeError(f"Hook failed for '{event}': {e}")
        return results

    def list_hooks(self):
        return {e: len(cbs) for e, cbs in self._hooks.items()}

