"""Middleware pipeline for task processing."""
from taskforge.core import ForgeError, create_forge


class Middleware:
    """Base middleware. Raises ForgeError on processing failure."""

    def __init__(self, name):
        self.name = name

    def process(self, task, next_fn):
        return next_fn(task)


class LoggingMiddleware(Middleware):
    """Logs task execution and catches ForgeError."""

    def __init__(self):
        super().__init__("logging")
        self.log = []

    def process(self, task, next_fn):
        self.log.append({"task": task, "event": "enter"})
        try:
            result = next_fn(task)
            self.log.append({"task": task, "event": "exit"})
            return result
        except ForgeError as e:
            self.log.append({"task": task, "event": "error", "error": str(e)})
            raise


class MiddlewarePipeline:
    """Chains middleware. Uses create_forge for pipeline context."""

    def __init__(self):
        self._middleware = []
        self._forge = create_forge("pipeline", {"max_workers": 2})

    def add(self, mw):
        if not isinstance(mw, Middleware):
            raise ForgeError(f"Expected Middleware, got {type(mw).__name__}")
        self._middleware.append(mw)

    def execute(self, task, handler):
        def build(i):
            if i >= len(self._middleware):
                return handler
            return lambda t: self._middleware[i].process(t, build(i + 1))
        return build(0)(task)

