"""Monitoring and health checks for the scheduling system."""
from taskforge.core import ForgeError, create_forge


class Monitor:
    """Tracks ForgeError occurrences and system health."""

    def __init__(self):
        self._errors = []
        self._checks = {}
        self._forge = create_forge("monitor", {"max_workers": 1})

    def record_error(self, error):
        """Record a ForgeError instance."""
        if not isinstance(error, ForgeError):
            raise TypeError(f"Expected ForgeError, got {type(error).__name__}")
        self._errors.append({"message": str(error), "code": error.code})

    def get_error_count(self):
        return len(self._errors)

    def register_check(self, name, check_fn):
        self._checks[name] = check_fn

    def run_checks(self):
        """Run health checks. Catches ForgeError from each."""
        results = {}
        for name, fn in self._checks.items():
            try:
                fn()
                results[name] = "healthy"
            except ForgeError as e:
                self.record_error(e)
                results[name] = f"unhealthy: {e}"
        return results

