"""Task registry for managing task type definitions."""
from taskforge.core import ForgeError, create_forge


class TaskRegistry:
    """Registry of task types. Raises ForgeError on conflicts."""

    def __init__(self):
        self._handlers = {}
        self._forges = {}

    def register(self, task_type, handler, config=None):
        """Register a handler. Raises ForgeError if duplicate."""
        if task_type in self._handlers:
            raise ForgeError(f"Type '{task_type}' already registered")
        self._handlers[task_type] = handler
        self._forges[task_type] = create_forge(f"reg-{task_type}", config)

    def get_handler(self, task_type):
        """Get handler. Raises ForgeError if missing."""
        if task_type not in self._handlers:
            raise ForgeError(f"No handler for '{task_type}'")
        return self._handlers[task_type]

    def get_forge(self, task_type):
        """Get forge created by create_forge for this type."""
        if task_type not in self._forges:
            raise ForgeError(f"No forge for '{task_type}'")
        return self._forges[task_type]

    def list_types(self):
        return list(self._handlers.keys())

