"""Retry logic for failed tasks."""
import time
from taskforge.core import ForgeError, create_forge


class RetryPolicy:
    """Retries operations that raise ForgeError."""

    def __init__(self, max_retries=3, backoff=0.01):
        self.max_retries = max_retries
        self.backoff = backoff
        self._history = []

    def execute_with_retry(self, func, *args, **kwargs):
        """Run func, retrying on ForgeError up to max_retries times."""
        last_error = None
        for attempt in range(self.max_retries + 1):
            try:
                return func(*args, **kwargs)
            except ForgeError as e:
                last_error = e
                self._history.append({"attempt": attempt, "error": str(e)})
                time.sleep(self.backoff)
        raise ForgeError(f"All {self.max_retries+1} attempts failed: {last_error}")

    def get_history(self):
        return list(self._history)


def create_retry_forge(name, config=None, max_retries=3):
    """Combine create_forge with RetryPolicy."""
    forge = create_forge(name=name, config=config)
    return forge, RetryPolicy(max_retries=max_retries)

