"""High-level scheduler orchestrating the full pipeline."""
from taskforge.core import ForgeError, create_forge
from taskforge.registry import TaskRegistry
from taskforge.dispatcher import Dispatcher
from taskforge.worker import Worker


class Scheduler:
    """Orchestrates registration, dispatch, and execution."""

    def __init__(self, config=None):
        self._registry = TaskRegistry()
        self._dispatcher = Dispatcher(self._registry)
        self._workers = []
        self._forge = create_forge("master", config)
        self._started = False

    def start(self):
        """Start scheduler. Raises ForgeError if already running."""
        if self._started:
            raise ForgeError("Scheduler already started")
        self._forge.start()
        self._started = True

    def stop(self):
        if not self._started:
            raise ForgeError("Scheduler not started")
        self._forge.stop()
        self._started = False

    def register_task(self, task_type, handler):
        self._registry.register(task_type, handler)

    def add_worker(self, worker_id=None):
        wid = worker_id or f"w-{len(self._workers)}"
        w = Worker(wid, self._registry)
        self._workers.append(w)
        return w

    def submit(self, task_type, payload=None):
        if not self._started:
            raise ForgeError("Cannot submit: not started")
        self._dispatcher.enqueue(task_type, payload)

    def run_next(self):
        if not self._workers:
            raise ForgeError("No workers available")
        task = self._dispatcher.dispatch_next()
        if task is None:
            return None
        return self._workers[0].execute(task["task_type"], task.get("payload"))

