"""Serialization utilities for task data."""
import json
from taskforge.core import ForgeError, create_forge


def serialize_error(error):
    """Serialize an error to dict."""
    if not isinstance(error, ForgeError):
        raise TypeError(f"Expected ForgeError, got {type(error).__name__}")
    return {"message": str(error), "code": error.code}


def deserialize_error(data):
    """Reconstruct an error from dict."""
    return ForgeError(message=data.get("message", ""), code=data.get("code"))


def validate_and_create(name, config_json):
    """Parse JSON config and build a forge via create_forge."""
    try:
        config = json.loads(config_json)
    except json.JSONDecodeError as e:
        raise ForgeError(f"Invalid JSON: {e}")
    return create_forge(name=name, config=config, strict=True)

