"""Worker module - executes tasks assigned by the dispatcher."""
from taskforge.core import ForgeError, create_forge


class Worker:
    """Executes tasks. Raises ForgeError on failures."""

    def __init__(self, worker_id, registry):
        self.worker_id = worker_id
        self._registry = registry
        self._results = []
        self._forge = create_forge(f"worker-{worker_id}", {"max_workers": 1})

    def execute(self, task_type, payload=None):
        """Execute a task. Raises ForgeError if handler missing."""
        try:
            handler = self._registry.get_handler(task_type)
        except ForgeError:
            raise ForgeError(f"Worker {self.worker_id}: no handler for '{task_type}'")
        try:
            result = handler(payload or {})
            self._results.append({"task_type": task_type, "status": "success"})
            return result
        except ForgeError:
            raise
        except Exception as e:
            raise ForgeError(f"Worker {self.worker_id}: '{task_type}' failed: {e}")

    def get_results(self):
        return list(self._results)
